 import java.util.Objects;
 import javax.annotation.Nullable;
+import okhttp3.Headers;

 /** Exception for an unexpected, non-2xx HTTP response. */
 public class HttpException extends RuntimeException {
@@ -50,4 +51,12 @@ public class HttpException extends RuntimeException {
   public @Nullable Response<?> response() {
     return response;
   }
+
+  /**
+   * The HTTP response headers. Returns {@code null} if the exception was serialized and
+   * {@link #response()} is not available.
+   */
+  public @Nullable Headers headers() {
+    return response != null ? response.headers() : null;
+  }
